var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"여러분, 괜찮으십니까?","JPN":"皆さん、ご無事ですか？","ENG":"Is everyone okay?","TWN":"大家，你們沒事吧？"},"stage":{"bg":"GRONIA_STREET","slots":{"L":null,"C":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"BASS_HARMONY_NULL_HIDE","text":{"KOREA":"아, 네. 저희는 다치지 않았어요. 그런데 레아가…….","JPN":"あ、はい。私たちは大丈夫です。でもレアが……","ENG":"Oh, yes. We’re fine, but Leah...","TWN":"嗯，我們沒事，可是蕾亞她……"},"stage":{"bg":"GRONIA_STREET","slots":{"L":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"GRONIA_STREET","slots":{"L":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"BASS_HARMONY_NULL_HIDE","text":{"KOREA":"왜…… 그러세요? 제 얼굴이 뭔가 이상한가요?","JPN":"どうか……しましたか？　私の顔に何か？","ENG":"Why are you looking at me like that? Is there something weird on my face?","TWN":"你……為什麼那樣盯著我？我臉上有東西嗎？"},"stage":{"bg":"GRONIA_STREET","slots":{"L":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"아, 아닙니다. 제가 개인적으로 존경하는 분과 닮으셔서요.","JPN":"あ、いいえ。私が個人的に尊敬している方と似ていらっしゃるので。","ENG":"Oh, it’s nothing. You remind me of someone I admire.","TWN":"沒…沒事，只是你長得很像我很尊敬的一個人。"},"stage":{"bg":"GRONIA_STREET","slots":{"L":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"여긴 교전에 휘말릴 수 있습니다. 저희 수송기로 이동하시죠.","JPN":"ここでは交戦に巻き込まれるかも知れません。私たちの輸送機へ移動しましょう。","ENG":"This place isn’t safe. We must get to the transport.","TWN":"在這裡會有危險，搭我們的運輸機離開吧！"},"stage":{"bg":"GRONIA_STREET","slots":{"L":null,"C":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"집으로…… 가면 안 돼요? 집에 가야 하는데……. 우리 딸애가 기다리고 있을 거야…….","JPN":"家に……行きたいです。家に帰らないと……娘が待ってるはずよ……","ENG":"Can’t we go... Home? I need to go home... My daughter will be waiting for me...","TWN":"我可以……回家嗎？我要回家……我女兒在家等我……"},"stage":{"bg":"GRONIA_STREET","slots":{"L":null,"C":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"아주머니, 정신 차려요! 따님은 지금 만신창이가 되어 있다고요!","JPN":"おばさん、しっかりして！　娘さんは今ボロボロになってますから！","ENG":"Madam, get a hold of yourself! Your daughter needs immediate medical attention!","TWN":"伯母，你冷靜點！妳女兒現在傷得很重！"},"stage":{"bg":"GRONIA_STREET","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"만신창이라니……. 엄마 걱정시키지는 마, 중사…….","JPN":"ボロボロって……お母さんが心配するじゃない、軍曹……","ENG":"Medical attention? ...Don’t make Mom worry, Sergeant.","TWN":"什麼傷得很重……中士，你不要亂說話嚇我媽……"},"stage":{"bg":"GRONIA_STREET","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"쿨럭……! 그런데 당신들은, 평범한 용병은 아닌 것 같은데…….","JPN":"ゴホッ……！　ところで君たちは、ただの傭兵ではなさそうだけど……","ENG":"*Cough!* But, you guys don’t look like ordinary mercenaries...","TWN":"咳咳……！你們感覺不像是普通的傭兵……"},"stage":{"bg":"GRONIA_STREET","slots":{"L":null,"C":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"관리국 직속 오피셜 서포트라고 알아 두시면 됩니다.","JPN":"管理局直属のオフィシャルサポートだと思ってください。","ENG":"We are called the Official Support, sent directly by the Administration.","TWN":"就當我們是管理局直屬的官方支援吧。"},"stage":{"bg":"GRONIA_STREET","slots":{"L":null,"C":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"자, 수송기 내부에 의료 설비가 갖춰져 있습니다. 절 따라오십시오.","JPN":"さあ、輸送機の内部に医療設備が備えられています。私についてきてください。","ENG":"There’s medical equipment in the transport. Follow me.","TWN":"跟我來，運輸機裡有醫療設備。"},"stage":{"bg":"GRONIA_STREET","slots":{"L":null,"C":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"이런, 예고르. 에스코트하는 데 방해됐으려나.","JPN":"あら、イェゴール。エスコートの邪魔をしたかしら？","ENG":"Ah, Yegor. Did I bother you in the middle of the escort?","TWN":"可惡，伊高爾，我有妨礙到你嗎？"},"stage":{"bg":"GRONIA_STREET","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"부전대장님?! 어디 안 다치셨습니까?","JPN":"副戦隊長！？　お怪我はありませんか？","ENG":"Deputy Commander?! Are you hurt?","TWN":"副戰隊長？！有沒有哪裡受傷？"},"stage":{"bg":"GRONIA_STREET","slots":{"L":null,"C":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"새삼스럽게. 이래봬도 카운터야. 한 대 정도 허용한다고 치명상까지 입진 않아.","JPN":"何を改まって。こう見えてもカウンターよ。一撃くらい食らっても致命傷にはならないわ。","ENG":"No problem. I’m a Counter. Such wounds won’t be enough to kill me.","TWN":"緊張什麼！我可是制裁者呢，被打幾下也不至於傷得多嚴重啦～"},"stage":{"bg":"GRONIA_STREET","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"그렇지만……. 상대가 소문 이상이긴 하네.","JPN":"でも……相手は想像以上だったわね。","ENG":"But still... Looks like she was more than just a rumor.","TWN":"不過……她比傳聞中還厲害呢！"},"stage":{"bg":"GRONIA_STREET","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};